window.__QUIZ_DATA__=[{"id":"objective>Civic Education>2017>1","subject":"Civic Education","year":"2017","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : DEFINITION","question":"The standards that are considered ethical by an individual or the society are known as","images":[],"options":{"A":"dignity","B":"rights","C":"values","D":"materialism"},"answer":"C","explanation":"The standards that are considered ethical by an individual or the society are known as values. Values are the beliefs and principles that guide our decisions and behavior. They are the standards by which we judge right and wrong, important and unimportant, worthwhile and worthless. They are not tangible items like dignity, rights or materialism, but rather intangible standards that guide our actions.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2017>2","subject":"Civic Education","year":"2017","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : IMPORTANCE OF VALUES TO SOCIETY","question":"One significance of value in society is that it","images":[],"options":{"A":"brings about peaceful co-existence of people","B":"makes one to acquire more properties","C":"enhances an individual's access to education","D":"promotes influx of aliens to community"},"answer":"A","explanation":"One significance of value in society is that it brings about peaceful co-existence of people. Values are the shared beliefs and attitudes that bind people together in society. They provide a common understanding of what is right and wrong, and this shared understanding helps to promote peace and harmony among people. The other options do not accurately represent the significance of values in society.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2017>3","subject":"Civic Education","year":"2017","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : THE NATIONALISTIC ROLES OF INDIVIDUALS AND GROUPS","question":"'If I should forsake you,  Banwuya motherland, Africa fatherland,  Let my two hands  Forget their cunnings\".   @ Femi Ademiluyi: The New Man.  All rights reserved.    The quotation shows that the speaker is","images":[],"options":{"A":"nationalistic","B":"opportunistic","C":"subservient","D":"reoriented"},"answer":"A","explanation":"The speaker in the poem is expressing a deep sense of loyalty and commitment to his motherland, Africa. This is a characteristic of nationalism, which is a political ideology that involves a strong identification of a group of individuals with a nation. Therefore, the speaker is nationalistic.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2017>4","subject":"Civic Education","year":"2017","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF CITIZENSHIP","question":"The status of being a legal member of a country is referred to as","images":[],"options":{"A":"alien","B":"asylum","C":"citizenship","D":"migrant"},"answer":"C","explanation":"The status of being a legal member of a country is referred to as citizenship. Citizenship is the status of a person recognized under the custom or law of a sovereign state or local jurisdiction. It involves rights, duties and privileges.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2017>5","subject":"Civic Education","year":"2017","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : IDENTIFICATION OF LOCAL AND WORLD CIVIC PROBLEMS","question":"Rendering services to humanity across boundaries is an indication of providing solution to","images":[],"options":{"A":"political crisis","B":"social dilemmas","C":"natural disasters","D":"civic problems"},"answer":"C","explanation":"Rendering services to humanity across boundaries is often in response to natural disasters. This is because natural disasters such as earthquakes, hurricanes, and floods often require international aid and assistance. This is not necessarily related to political crisis, social dilemmas, or civic problems, which are more localized and specific issues.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2017>6","subject":"Civic Education","year":"2017","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : ROLES OF INDIVIDUALS, GROUPS AND GOVERNMENT IN UDHR","question":"Human rights can be best promoted if","images":[],"options":{"A":"jungle justice is discouraged","B":"relevant knowledge and information are acquired","C":"political elite exercises discretionary powers","D":"there is existing constitution"},"answer":"B","explanation":"Human rights can be best promoted if relevant knowledge and information are acquired. This is because understanding the concept of human rights, the laws that protect these rights, and the mechanisms to enforce these rights is crucial for their promotion. While discouraging jungle justice, exercising discretionary powers by political elites, and having an existing constitution can contribute to the promotion of human rights, they are not as fundamental as having the relevant knowledge and information.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2017>7","subject":"Civic Education","year":"2017","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : CATEGORIES OF HUMAN RIGHTS","question":"The rights of citizens can be guaranteed through","images":[],"options":{"A":"gerrymandering","B":"the writ of habeas corpus","C":"prerogative of mercy","D":"political immunity"},"answer":"B","explanation":"The writ of habeas corpus is a legal action or writ by means of which detainees can seek relief from unlawful imprisonment. It is a way to report an illegal detention or imprisonment to a court and request that the court order the custodian of the person, usually a prison official, to bring the prisoner to court, to determine whether the detention is lawful. This is how it guarantees the rights of citizens.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2017>8","subject":"Civic Education","year":"2017","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : CATEGORIES OF HUMAN RIGHTS","question":"The inalienable rights of citizens of a state can best be protected through","images":[],"options":{"A":"an unwritten constitution","B":"parliamentary system of government","C":"unitary system of government","D":"an independent judiciary"},"answer":"D","explanation":"An independent judiciary is the best way to protect the inalienable rights of citizens of a state. This is because an independent judiciary can make decisions free from pressure and influences other than the law. It can uphold the rule of law, protect rights and liberties, and check abuses of power. An independent judiciary ensures that everyone, including citizens, institutions, and the government itself, are subject to the law.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2017>9","subject":"Civic Education","year":"2017","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE OF LAW AND ORDER IN THE SOCIETY","question":"The society can be much more peaceful if individuals learn to","images":[],"options":{"A":"respect and obey the laws of the land","B":"gather knowledge about politics","C":"understand the human rights commission","D":"seek redress in the court of law"},"answer":"A","explanation":"A peaceful society is one where law and order are maintained. This can be achieved if individuals respect and obey the laws of the land. This is because laws are designed to regulate human behavior and maintain order in society. When people obey the laws, conflicts and crimes are minimized, leading to a peaceful society.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2017>10","subject":"Civic Education","year":"2017","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : DEFINITION OF LAW AND ORDER","question":"The exhibition of queuing culture in a society is a good example of","images":[],"options":{"A":"participation","B":"empowerment","C":"nationalism","D":"orderliness"},"answer":"D","explanation":"Queuing culture is a practice where people line up in an orderly manner while waiting for services or goods. This practice is a good example of orderliness because it shows respect for others and prevents chaos and confusion. It is not directly related to participation, empowerment, or nationalism.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2017>11","subject":"Civic Education","year":"2017","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : MEANING OF CONSTITUTED AUTHORITY","question":"Constituted authority is necessary in the society because it","images":[],"options":{"A":"promotes international relations","B":"ensures security of lives and properties","C":"serves as agent of socialization","D":"provides scholarship for higher education"},"answer":"B","explanation":"Constituted authority refers to the powers and mechanisms established by a constitution, which govern a society or organization. It is necessary in society because it ensures the security of lives and properties. This is achieved by enforcing laws and regulations, maintaining order, and protecting citizens from harm.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2017>12","subject":"Civic Education","year":"2017","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : IMPORTANCE OF RESPONSIBLE PARENTHOOD IN NATIONAL DEVELOPMENT","question":"Responsible parenthood is important because it","images":[],"options":{"A":"promotes procreation","B":"fosters orderliness","C":"grooms disciplined children","D":"provides solution to all societal problems"},"answer":"C","explanation":"Responsible parenthood refers to the responsibility of parents to guide, nurture, and instill good values in their children. It is important because it grooms disciplined children. Disciplined children are more likely to grow into responsible adults who contribute positively to society.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2017>13","subject":"Civic Education","year":"2017","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : ROLES OF RESPONSIBLE PARENTS","question":"Which of the following should not be encouraged by responsible parents?","images":[],"options":{"A":"Moral development","B":"Religious fundamentalism","C":"Spiritual development","D":"Respect for elders"},"answer":"B","explanation":"Responsible parents should encourage moral development, spiritual development, and respect for elders in their children. However, religious fundamentalism, which refers to a belief in the absolute authority of a religious text or leaders, is often associated with intolerance and extremism. Therefore, it should not be encouraged.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2017>14","subject":"Civic Education","year":"2017","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : MEANING OF TRAFFIC REGULATIONS","question":"Road signs primarily serve as","images":[],"options":{"A":"symbols to correct road users","B":"signs to aid Federal Road Safety officials to apprehend defaulters","C":"devices to guide traffic division of Police Command","D":"precautionary devices to guide road users"},"answer":"D","explanation":"Road signs are primarily used as precautionary devices to guide road users. They provide information about the road conditions ahead, provide directions and destinations, and enforce traffic laws. They are not primarily symbols to correct road users, signs to aid Federal Road Safety officials to apprehend defaulters, or devices to guide the traffic division of Police Command.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2017>15","subject":"Civic Education","year":"2017","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : THE ROLES OF THE INDIVIDUAL AND GOVERNMENT IN MAINTAINING TRAFFIC REGULATIONS","question":"In obeying traffic rules, pedestrians are to walk on the left side of the road so as to","images":[],"options":{"A":"buy things at the roadside","B":"see oncoming vehicles","C":"cross at anytime","D":"walk across junctions"},"answer":"B","explanation":"Pedestrians are advised to walk on the left side of the road to see oncoming vehicles. This is a safety measure that allows pedestrians to see approaching vehicles and take necessary actions to avoid accidents. It has nothing to do with buying things at the roadside, crossing at anytime or walking across junctions.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2017>16","subject":"Civic Education","year":"2017","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : WAYS OF PREVENTING CULTISM IN SOCIETY","question":"Use the diagram below to answer this question      From the diagram above, activities of deviants in the society can be curtailed by","images":["data:image/png;base64,"],"options":{"A":"establishment of more prison","B":"ostracizing the deviants from the society","C":"indulging the deviants with financial incentive","D":"strengthening reformative institutions"},"answer":"D","explanation":"From the diagram above, activities of deviants in the society can be curtailed by strengthening reformative institution.","marks":"1","difficulty":"3"},{"id":"objective>Civic Education>2017>17","subject":"Civic Education","year":"2017","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : SKILLS THAT PROMOTE INTERPERSONAL RELATIONSHIPS","question":"Use the diagram below to answer this question    The act of the deviants in the picture above contradicts the skills of","images":["data:image/png;base64,"],"options":{"A":"interpersonal relationships","B":"entrepreneurship","C":"inter-communal relationships","D":"resolution"},"answer":"A","explanation":"The act of the deviants in the picture above contradicts the skills of Inter personal relationships.","marks":"1","difficulty":"3"},{"id":"objective>Civic Education>2017>18","subject":"Civic Education","year":"2017","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : SKILLS FOR RESOLVING INTER-COMMUNAL CONFLICTS","question":"One of the skills that can be used in resolving intercommunal conflicts is","images":[],"options":{"A":"coercion","B":"mediation","C":"suppression","D":"harassment"},"answer":"B","explanation":"Mediation is a conflict resolution skill that can be used in resolving intercommunal conflicts. Mediation involves a neutral third party who helps the conflicting parties to reach a mutually satisfactory agreement. Coercion, suppression, and harassment are not effective conflict resolution skills as they may lead to further escalation of the conflict.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2017>19","subject":"Civic Education","year":"2017","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM","question":"Use the dialogue below to this question   Johnson: Danladi, when are you leaving for school?  Danladi: School?  Johnson: Are you on break?  Danladi: No, but the school has been closed down due to clash between rival cult groups.  Johnson: What a terrible situation! I don't know when you are going to finish your programme. You have already spent six years in school for a four-year programme due to frequent closure and compulsory breaks. So what will you be doing at home while the closure lasted?  Danladi: Roaming the street, visiting friends and attending social functions of course.  Johnson: You better engage yourself in a productive venture such as learning a new language, entrepreneurial skills, volunteer services and so on.    From the above dialogue, it is evident that cultism disrupts activities in the","images":[],"options":{"A":"family","B":"school","C":"society","D":"club"},"answer":"B","explanation":"From the dialogue, it is clear that the activities being disrupted by cultism are those of the school. Danladi mentions that the school has been closed down due to clashes between rival cult groups, which has extended his four-year programme to six years. Therefore, the correct answer is 'school'.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2017>20","subject":"Civic Education","year":"2017","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM","question":"Use the dialogue below to this question   Johnson: Danladi, when are you leaving for school?  Danladi: School?  Johnson: Are you on break?  Danladi: No, but the school has been closed down due to clash between rival cult groups.  Johnson: What a terrible situation! I don't know when you are going to finish your programme. You have already spent six years in school for a four-year programme due to frequent closure and compulsory breaks. So what will you be doing at home while the closure lasted?  Danladi: Roaming the street, visiting friends and attending social functions of course.  Johnson: You better engage yourself in a productive venture such as learning a new language, entrepreneurial skills, volunteer services and so on.  From the above dialogue, which of the following is likely to happen if cultism is eradicated from our campuses?","images":[],"options":{"A":"Uninterrupted school programme","B":"Increase in the remuneration of staff of higher institutions","C":"Provision of scholarships for brilliant students","D":"Amicable resolution of disputes on campuses"},"answer":"A","explanation":"The dialogue suggests that the eradication of cultism would lead to an uninterrupted school programme. This is evident from Johnson's concern about Danladi's extended stay in school due to frequent closures and compulsory breaks, which are a result of the cult activities. Therefore, the correct answer is 'Uninterrupted school programme'.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2017>21","subject":"Civic Education","year":"2017","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : REASONS FOR CULTISM","question":"Which of the following is not responsible for cult activities in schools and colleges?","images":[],"options":{"A":"Perceived injustice","B":"Satisfaction of membership aspiration","C":"Personal protection","D":"Preservation of cultural heritage"},"answer":"D","explanation":"Cult activities in schools and colleges are often driven by factors such as perceived injustice, satisfaction of membership aspiration, and personal protection. However, preservation of cultural heritage is not a common reason for cult activities. Cults are often associated with negative behaviors and practices that are contrary to cultural heritage preservation.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2017>22","subject":"Civic Education","year":"2017","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : SYMPTOMS OF DRUG ABUSE","question":"Drug abuse often leads to","images":[],"options":{"A":"sexually transmitted disease","B":"cancerous illness","C":"psychiatric disorder","D":"incurable ailment"},"answer":"C","explanation":"Drug abuse can lead to a variety of health problems, including psychiatric disorders. The use of drugs can alter the brain's structure and function, leading to changes in mood, behavior, and cognitive processes. This can result in psychiatric disorders such as depression, anxiety, and psychosis. While drug abuse can also lead to sexually transmitted diseases, cancerous illnesses, and incurable ailments, these are not direct consequences of drug abuse but rather potential indirect consequences.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2017>23","subject":"Civic Education","year":"2017","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : WAYS OF PREVENTING DRUG ABUSE","question":"Use of hard drugs could best be curtailed through","images":[],"options":{"A":"compensation","B":"rehabilitation","C":"enlightenment","D":"compromise"},"answer":"C","explanation":"The use of hard drugs can best be curtailed through enlightenment. This involves educating people about the dangers and negative effects of hard drugs on their health and society at large. This is more effective than compensation or compromise, which may not address the root cause of the problem. Rehabilitation is also important, but it comes after the person has already started using drugs. Enlightenment, on the other hand, can prevent the person from starting to use drugs in the first place.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2017>24","subject":"Civic Education","year":"2017","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS","question":"If an individual persists in the use of hard drugs, such individual is likely to exhibit","images":[],"options":{"A":"hostile attitude towards religious organizations","B":"unfriendly disposition towards foreigners","C":"oppressive behaviour","D":"emotional illness and aggression"},"answer":"D","explanation":"Persistent use of hard drugs often leads to emotional illness and aggression. This is because drugs can alter the brain's structure and function, leading to changes in mood, behavior, and cognition. This can manifest as emotional instability, irritability, and aggressive behavior. The other options, such as hostile attitude towards religious organizations, unfriendly disposition towards foreigners, and oppressive behavior, are not directly linked to drug use.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2017>25","subject":"Civic Education","year":"2017","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : WAYS OF PREVENTING DRUG ABUSE","question":"Drug abuse can best be prevented in the society by","images":[],"options":{"A":"arresting and prosecuting drug vendors","B":"engaging in public enlightenment","C":"canvassing capital punishment for drug peddlers","D":"prohibiting the sales of drugs at the motor park"},"answer":"B","explanation":"Public enlightenment is the best way to prevent drug abuse in society. This is because it involves educating the public about the dangers and consequences of drug abuse. It helps to change people's attitudes and behaviors towards drug use. Arresting and prosecuting drug vendors or canvassing capital punishment for drug peddlers may deter some people, but it does not address the root cause of the problem. Prohibiting the sales of drugs at the motor park is also not a comprehensive solution as drugs can be sold elsewhere.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2017>26","subject":"Civic Education","year":"2017","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : MEANING OF HUMAN TRAFFICKING","question":"Which of the following people suffer most in human trafficking?","images":[],"options":{"A":"Girls","B":"Boys","C":"Children","D":"Adults"},"answer":"C","explanation":"Children suffer most in human trafficking. This is because they are often the most vulnerable and easy to manipulate. They are often forced into labor, sexual exploitation, and other forms of abuse. While girls, boys, and adults can also be victims of human trafficking, children are often the most affected due to their vulnerability.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2017>27","subject":"Civic Education","year":"2017","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : MEANING OF HUMAN TRAFFICKING","question":"Which of the following people suffer most in human trafficking?","images":[],"options":{"A":"Girls","B":"Boy","C":"Children","D":"Adults"},"answer":"C","explanation":"Human trafficking affects all demographics, but children are often the most vulnerable. This is due to their lack of understanding, inability to protect themselves, and the fact that they are often targeted by traffickers due to their vulnerability. Therefore, the answer is 'Children'.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2017>28","subject":"Civic Education","year":"2017","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : CAUSES OF HUMAN TRAFFICKING","question":"Which of the following cannot motivate human trafficking?","images":[],"options":{"A":"Poverty","B":"Greed","C":"Low self-esteem","D":"Education"},"answer":"D","explanation":"Education is a tool that empowers individuals and provides them with the knowledge and skills to protect themselves. It is not a motivator for human trafficking. On the contrary, it is often a deterrent. The other options, such as poverty, greed, and low self-esteem, can all contribute to the conditions that make individuals vulnerable to trafficking.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2017>29","subject":"Civic Education","year":"2017","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : CAUSES OF HIV/AIDS","question":"One way of being infected with HIV/AIDS is through","images":[],"options":{"A":"the use of unsterilized sharp objects","B":"sitting close to HIV/AIDS infected persons","C":"sharing clothes with AIDS/HIV infected persons","D":"having handshake with people living with HIV/AIDS"},"answer":"A","explanation":"HIV/AIDS can be transmitted through the use of unsterilized sharp objects. This is because the virus can survive in the blood on these objects and infect a person if they come into contact with their bloodstream. It cannot be transmitted through casual contact such as sitting close to, sharing clothes with, or shaking hands with a person living with HIV/AIDS.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2017>30","subject":"Civic Education","year":"2017","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : PREVENTION OF HIV/AIDS","question":"One of the preventive measures against the infection of HIV/AIDS is","images":[],"options":{"A":"membership of Red Cross Society","B":"faithfulness to a partner","C":"becoming a medical staff","D":"membership of campaign against AIDS"},"answer":"B","explanation":"One of the most effective preventive measures against the infection of HIV/AIDS is being faithful to a partner. This reduces the risk of exposure to the virus through sexual contact. Membership of organizations like the Red Cross Society or a campaign against AIDS, or becoming a medical staff, while potentially beneficial in the fight against HIV/AIDS, are not direct preventive measures against the infection.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2017>31","subject":"Civic Education","year":"2017","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : YOUTH EMPOWERMENT SKILLS","question":"Which of the following is not a skill for practical living?","images":[],"options":{"A":"Life coping skill","B":"Manipulative skill","C":"Artistic skill","D":"Cyber crime skill"},"answer":"D","explanation":"Practical living skills are those skills that are essential for living independently. These include life coping skills, manipulative skills, and artistic skills. Life coping skills help individuals to handle issues and problems commonly encountered in daily life. Manipulative skills are those that require movement and coordination of the hands and fingers, and artistic skills involve creativity and the ability to create art. Cyber crime skill, however, is not a skill for practical living. It involves illegal activities using the internet and is not a skill that promotes independent and responsible living.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2017>32","subject":"Civic Education","year":"2017","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : IMPORTANCE AND BENEFITS OF YOUTH EMPOWERMENT SKILLS","question":"Which of the following is not a reason for self-reliance?","images":[],"options":{"A":"Creation of employment opportunities","B":"Innovation and creativity","C":"Diversification of the economy","D":"Quest for white collar jobs"},"answer":"D","explanation":"Self-reliance is the ability to depend on oneself for the things one needs. The reasons for self-reliance include the creation of employment opportunities, innovation and creativity, and diversification of the economy. These all contribute to personal growth and economic development. However, the quest for white collar jobs is not a reason for self-reliance. In fact, it can be seen as a reliance on others or on a particular sector of the economy, which is contrary to the concept of self-reliance.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2017>33","subject":"Civic Education","year":"2017","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT","question":"In the constitution, the areas where both the federal and state governments exercise joint authority are on the","images":[],"options":{"A":"residual list","B":"concurrent list","C":"exclusive list","D":"reserved list"},"answer":"B","explanation":"In a federal system of government, the concurrent list refers to the areas where both the federal and state governments can exercise authority. This includes areas like education, agriculture, health, etc. The residual list is for the state government, the exclusive list is for the federal government, and there is no such thing as a reserved list in the constitution.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2017>34","subject":"Civic Education","year":"2017","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : FUNCTIONS OF GOVERNMENT","question":"Government is saddled with all the following responsibilities except","images":[],"options":{"A":"prevention of internal disturbances","B":"protection of lives and properties","C":"promotion of industrial development","D":"provision of all needs of the citizens"},"answer":"D","explanation":"While the government is responsible for the prevention of internal disturbances, protection of lives and properties, and promotion of industrial development, it is not responsible for the provision of all needs of the citizens. This is because in a democratic society, citizens also have personal responsibilities and the government cannot cater to every individual need.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2017>35","subject":"Civic Education","year":"2017","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : FEATURES OF RULE OF LAW","question":"A major feature of representative democracy is","images":[],"options":{"A":"free and fair election","B":"absolute application of law","C":"civil liberty groups","D":"enlightened electorates"},"answer":"A","explanation":"A major feature of representative democracy is free and fair election. In a representative democracy, citizens elect representatives to make decisions and pass laws on behalf of all the people instead of the people deciding on laws themselves. Free and fair elections are a fundamental part of this process, ensuring that the representatives truly reflect the will of the people.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2017>36","subject":"Civic Education","year":"2017","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING, TYPES, AND FEATURES OF DEMOCRACY;","question":"A feature that distinguishes the 1979 Nigerian constitution from that of 1963 was the introduction of","images":[],"options":{"A":"unitary system of government","B":"republicanism","C":"presidential system of government","D":"westminster system"},"answer":"C","explanation":"The 1979 Nigerian constitution introduced the presidential system of government, which was a departure from the parliamentary system of government that was in place under the 1963 constitution. In a presidential system, the president is both the head of state and the head of government, and is separate from the legislature. This is different from a parliamentary system, where the head of state is usually a monarch or president, but the head of government is the prime minister or premier, and is a member of the legislature.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2017>37","subject":"Civic Education","year":"2017","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : HOW DEMOCRACY AND RULE OF LAW PROMOTE NATIONAL DEVELOPMENT- GOOD GOVERNANCE, EMPLOYMENT CREATION AND POVERTY ALLEVIATION ETC","question":"In a democracy, official opposition is allowed to","images":[],"options":{"A":"bring down the government","B":"pave way for military intervention","C":"make government accountable","D":"encourage crisis in a state"},"answer":"C","explanation":"In a democracy, the role of the official opposition is to hold the government accountable for its actions. They do this by scrutinizing the government's policies and actions, and by offering alternative policies. They do not have the power to bring down the government, pave way for military intervention, or encourage crisis in a state.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2017>38","subject":"Civic Education","year":"2017","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : IMPORTANCE OF DEMOCRACY","question":"The beauty of democratic system of government is that","images":[],"options":{"A":"the President has supreme power","B":"political power resides in the people","C":"there is absence of exploitation","D":"political participation is limited"},"answer":"B","explanation":"The beauty of a democratic system of government is that political power resides in the people. This is because in a democracy, the people are the ultimate source of political power. They exercise this power directly or through their elected representatives. The other options are not correct because in a democracy, the President does not have supreme power, there is not necessarily an absence of exploitation, and political participation is not limited.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2017>39","subject":"Civic Education","year":"2017","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING OF RULE OF LAW","question":"Use the passage below to answer this question   One morning, Mr. Ojuri was on his way to a bank in his neighbourhood to make enquiries. He was arrested for wandering and subsequently detained for seven days by the police without trial or access to his relatives.    From the above passage, it could be said that in a society where this incident happened, there is absence of","images":[],"options":{"A":"court of law","B":"rule of law","C":"lawyers and solicitors","D":"the press"},"answer":"B","explanation":"The rule of law is a principle that ensures that all individuals and institutions are subject to and accountable to laws that are fairly applied and enforced. In the scenario described, Mr. Ojuri was arrested and detained without trial or access to his relatives, which is a violation of his rights. This indicates an absence of the rule of law, as his rights were not protected by the law. Therefore, the correct answer is 'rule of law'.","marks":"1","difficulty":"3"},{"id":"objective>Civic Education>2017>40","subject":"Civic Education","year":"2017","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : MEANING OF POLITICAL APATHY","question":"The following can be classified as forms of political apathy except","images":[],"options":{"A":"refusal to register and vote","B":"lack of interest in politics","C":"refusal to rig in an election","D":"nonchalant attitude towards politicians"},"answer":"C","explanation":"Political apathy refers to a lack of interest, enthusiasm, or concern about political matters. This can manifest in various ways, such as refusal to register and vote, lack of interest in politics, or a nonchalant attitude towards politicians. However, 'refusal to rig in an election' is not a form of political apathy. Rather, it is an act of political integrity and adherence to democratic principles. Therefore, the correct answer is 'refusal to rig in an election'.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2017>41","subject":"Civic Education","year":"2017","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : MEANING OF POLITICAL APATHY","question":"The notion of perceiving the involvement of people in politics as devilish connotes political","images":[],"options":{"A":"demonization","B":"apathy","C":"degeneration","D":"discontent"},"answer":"A","explanation":"The notion of perceiving the involvement of people in politics as devilish connotes political 'demonization'. Demonization in this context refers to the act of portraying something as wicked or threatening, in this case, the involvement in politics.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2017>42","subject":"Civic Education","year":"2017","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : ACHIEVING POPULAR PARTICIPATION IN POLITICS","question":"The active involvement of people in the decision-making process in a state indicates political","images":[],"options":{"A":"indoctrination","B":"participation","C":"struggle","D":"apathy"},"answer":"B","explanation":"The active involvement of people in the decision-making process in a state indicates political 'participation'. Political participation refers to the actions of private citizens by which they seek to influence or support government and politics.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2017>43","subject":"Civic Education","year":"2017","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF CIVIL SOCIETY","question":"A non-governmental organisation that allows independent initiative of citizens is known as","images":[],"options":{"A":"civil society","B":"pressure group","C":"religious group","D":"professional society"},"answer":"A","explanation":"A civil society is a term often used to describe the wide array of non-governmental and not-for-profit organizations that have a presence in public life, expressing the interests and values of their members or others, based on ethical, cultural, political, scientific, religious or philanthropic considerations. Civil societies are often populated by organizations such as registered charities, development non-governmental organizations, community groups, women's organizations, faith-based organizations, professional associations, trade unions, self-help groups, social movements, business associations, coalitions and advocacy groups.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2017>44","subject":"Civic Education","year":"2017","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : ACHIEVING POPULAR PARTICIPATION IN POLITICS","question":"The effective way by which government can ascertain public support and reaction is through","images":[],"options":{"A":"opinion leaders","B":"party members","C":"campaigns","D":"elections"},"answer":"D","explanation":"Elections are the most effective way by which government can ascertain public support and reaction. Elections are a formal group decision-making process by which a population chooses an individual or multiple individuals to hold public office. They are the mechanism by which a country gauges the general public's opinion on governmental policies and actions.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2017>45","subject":"Civic Education","year":"2017","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : CONSEQUENCES OF POLITICAL APATHY","question":"The following are effects of political apathy except that it","images":[],"options":{"A":"affects the quality of lives","B":"leads to the enthronement of irresponsible leaders","C":"promotes free and fair elections","D":"ensures non-availability of dividends of democracy"},"answer":"C","explanation":"Political apathy refers to indifference in the attitude of citizens towards political activities. It often leads to low voter turnout and lack of political control by the people. This can result in irresponsible leaders and a lack of dividends of democracy, affecting the quality of lives. However, it does not promote free and fair elections. Instead, it can lead to unrepresentative outcomes in elections.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2017>46","subject":"Civic Education","year":"2017","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : ACHIEVING POPULAR PARTICIPATION IN POLITICS","question":"Which of the following is the best way through which citizens can participate in the politics of their country?","images":[],"options":{"A":"Acquisition of higher degree in political science","B":"Standing for elective positions","C":"Learning the arts and science of political sagacity","D":"Undergoing mentorship under prominent political leaders"},"answer":"B","explanation":"Citizens can participate in the politics of their country in various ways, such as voting, standing for elective positions, joining political parties, and engaging in political discussions. Among the options provided, standing for elective positions is the most direct way of participating in politics. It allows citizens to influence political decisions and policies directly. The other options, while they can contribute to political knowledge and skills, do not necessarily involve direct participation in politics.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2017>47","subject":"Civic Education","year":"2017","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : FUNCTIONS OF PUBLIC SERVICE","question":"The public service is important for ensuring","images":[],"options":{"A":"continuity in governance","B":"gender equality","C":"professional equality","D":"superiority of the pressure groups"},"answer":"A","explanation":"The public service is a sector of the government that ensures continuity in governance. It is the machinery of the government responsible for the implementation of laws and policies, and it continues to function regardless of changes in government. Therefore, the public service ensures continuity in governance.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2017>48","subject":"Civic Education","year":"2017","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : FUNCTIONS OF PUBLIC SERVICE","question":"Political neutrality of civil servants means that they","images":[],"options":{"A":"do not engage in partisan politics","B":"should not be seen or heard","C":"should not work with politicians","D":"do not receive praises nor blames for their actions"},"answer":"A","explanation":"Political neutrality of civil servants means that they do not engage in partisan politics. Civil servants are expected to serve the government of the day, regardless of its political affiliation, and to implement its policies impartially. Therefore, they should not engage in partisan politics to maintain their impartiality and integrity.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2017>49","subject":"Civic Education","year":"2017","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : FUNCTIONS OF PUBLIC SERVICE","question":"The category of public service that has the closest contact with the political class is the","images":[],"options":{"A":"manipulative class","B":"administrative class","C":"clerical class","D":"technical class"},"answer":"B","explanation":"The administrative class in the public service has the closest contact with the political class. This is because the administrative class is responsible for implementing the policies and decisions made by the political class. They are the bridge between the political class and the rest of the public service.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2017>50","subject":"Civic Education","year":"2017","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : PROBLEMS OF PUBLIC SERVICE","question":"In the public service, another name for red-tapism is","images":[],"options":{"A":"theocracy","B":"bureaucracy","C":"autocracy","D":"democracy"},"answer":"B","explanation":"In the public service, another name for red-tapism is bureaucracy. Red-tapism refers to the excessive regulation or rigid conformity to formal rules that is considered redundant or bureaucratic and hinders or prevents action or decision-making. It is usually applied to governments, corporations, and other large organizations.","marks":"1","difficulty":"2"}];